import{A as n}from"./chunks/theme.BnJirLdI.js";import{u as i}from"./chunks/link-icons.fvmyrjZg.js";import{c as a}from"./chunks/encryption.S1_HwLux.js";import{_ as s}from"./chunks/CanvasViewer.vue_vue_type_script_setup_true_lang.BaEQOOyt.js";import{a3 as r,o as l,c as o,ah as t,v as d,s as c}from"./chunks/framework.cbxun9lb.js";import"./chunks/index.Difenjld.js";const w=JSON.parse('{"title":"Obsidian WebDAV Sync","titleTemplate":"WebDAV Syncing Plugin for Obsidian","description":"WebDAV Sync is a plugin for Obsidian that syncs your vault with a WebDAV server. It excels existing solutions at reliable bidirectional syncing, better performance and the freedom from vendor lock-in.","frontmatter":{"layout":"project","title":"Obsidian WebDAV Sync","titleTemplate":"WebDAV Syncing Plugin for Obsidian","description":"WebDAV Sync is a plugin for Obsidian that syncs your vault with a WebDAV server. It excels existing solutions at reliable bidirectional syncing, better performance and the freedom from vendor lock-in.","logo":"https://github.com/hesprs/obsidian-webdav-sync/raw/main/assets/logo.svg","links":[{"name":"GitHub Repository","url":"https://github.com/hesprs/obsidian-webdav-sync","color":"#010409"}],"head":[["meta",{"name":"keywords","content":"Obsidian, Obsidian plugin, Obsidian WebDAV Sync, Obsidian WebDAV, WebDAV synchronization, cross-device sync"}]]},"headers":[],"relativePath":"projects/obsidian-webdav-sync.md","filePath":"en/projects/obsidian-webdav-sync.md","lastUpdated":1777984396000}'),g={name:"projects/obsidian-webdav-sync.md"},x=r({...g,setup(h){return i({"GitHub Repository":n}),(u,e)=>(l(),o("div",null,[e[0]||(e[0]=t('<h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to “Introduction”">​</a></h2><p>Obsidian WebDAV Sync is a general-purpose &amp; bidirectional WebDAV syncing plugin for Obsidian. It is created due to the current landscape that no single plugin can reliably and conveniently sync your vault with a WebDAV server. It excels existing solutions at reliable bidirectional syncing, better performance and the freedom from vendor lock-in:</p><p>🔄 <strong>Reliable Bidirectional Syncing</strong>:</p><ul><li>This plugin syncs your vault with a WebDAV storage.</li><li>It does three-way comparison: remote state, local state, and recorded local &amp; remote states of last sync</li><li>Then it follows a decision matrix for maximum precision and data integrity, detail see <a href="#technical-breakdown">below</a>.</li></ul><p>🔀 <strong>Auto Sync and Conflict Handling</strong>:</p><ul><li>The plugin supports automatically triggered sync as follows: <ul><li><strong>Startup sync</strong>: trigger a sync when Obsidian starts.</li><li><strong>Scheduled sync</strong>: trigger syncs periodically.</li><li><strong>Real-time sync</strong>: trigger syncs immediately when a change is detected.</li></ul></li><li>The plugin supports conflict handling methods: <ul><li>Smart merge</li><li>Latest survive</li><li>Use remote</li><li>Use local</li><li>Skip</li></ul></li></ul><p>🔐 <strong>Client-side Encryption</strong>:</p><ul><li>This plugin supports encrypting your files before uploading.</li><li>It prevents unauthorized file access, and detects unintended file modification and movement at remote side.</li><li>The encryption pipeline assumes stricter threat model, and achieves <strong>theoretically higher security, faster performance and smaller plugin size</strong> than similar solutions (like Remotely Save), see detail in the <a href="https://github.com/hesprs/obsidian-webdav-sync/blob/main/docs/encryption.md" target="_blank" rel="noreferrer">encryption specification</a>.</li></ul><p>⚡ <strong>Maximum Performance</strong>:</p><ul><li>Most sync operations are performed via parallelized network requests.</li><li>Real-time sync uses cached remote states by default, allowing it to complete syncing within seconds.</li><li><strong>10 times</strong> smaller size than Remotely Save, <strong>8 times</strong> faster startup loading time.</li></ul><p>🧰 <strong>Detailed Config</strong>:</p><ul><li>The plugin allows users to adjust various parameters to adapt for various services: <ul><li><strong>Max concurrent WebDAV requests</strong>: deal with service rate limiting.</li><li><strong>Min time between WebDAV requests</strong>: deal with service rate limiting.</li><li><strong>Skip large files</strong>: handle low storage space.</li><li><strong>Max concurrent sync tasks</strong>: control CPU and disk usage.</li><li><strong>Max concurrent throughput</strong>: control memory usage and prevent crashes.</li></ul></li></ul><p>📦 <strong>Production-Level Scalability</strong>:</p><ul><li>Handles vaults with more than 3000 files smoothly.</li><li>Load balancing and download chunking allows the plugin to handle gigabytes at once.</li><li>Large file downloading is resumable.</li></ul><p>🎨 <strong>Excellent UI and Observability</strong>:</p><ul><li>Four ways (modals, status bar, notices, logs) to keep you aware of the syncing progress.</li><li>File changes are rendered as a file tree to allow granular selective syncing.</li><li>Log utility outputs human-readable markdown documents.</li></ul><h2 id="another-syncing-plugin" tabindex="-1">Another Syncing Plugin? <a class="header-anchor" href="#another-syncing-plugin" aria-label="Permalink to “Another Syncing Plugin?”">​</a></h2><p>As an Obsidian user working across multiple devices, I&#39;ve personally encountered the sync dilemma: finding a solution that&#39;s reliable, flexible, and doesn&#39;t compromise data integrity. After trying nearly every syncing plugin in the community, I found that each came with trade-offs that frustrated my daily workflow:</p><ul><li><strong>Remotely Save</strong> offers comprehensive features but suffers from maintenance issues and bugs—deleted files mysteriously reappearing (which is the <strong>very</strong> reason that drove me quit).</li><li><strong>Syncthing Integration</strong> provides excellent P2P syncing but requires all devices to be online simultaneously.</li><li><strong>Live Sync</strong> delivers robustness at the cost of complex server setup.</li><li><strong>Git-based solutions</strong> excels at version control but is not designed for seamless daily synchronization.</li></ul><p>Then I discovered <a href="https://github.com/nutstore/obsidian-nutstore-sync" target="_blank" rel="noreferrer">Nutstore Sync</a> — an excellent plugin, but designed for Nutstore only. I thought: why not make this general-purpose? So I forked it, extensively overhauled it for no vendor lock-in, better performance, and improved stability. What came out was <strong>Obsidian WebDAV Sync</strong>.</p><h2 id="technical-breakdown" tabindex="-1">Technical Breakdown <a class="header-anchor" href="#technical-breakdown" aria-label="Permalink to “Technical Breakdown”">​</a></h2><h3 id="file-handling" tabindex="-1">File Handling <a class="header-anchor" href="#file-handling" aria-label="Permalink to “File Handling”">​</a></h3><p>To sync an Obsidian vault to a WebDAV server is a typical <strong>distributed coordination</strong> problem, where each client has their own copy and changes of the vault and there&#39;s no centralized resolver between. The goal is to synchronize the vaults between clients for maximum data integrity.</p><p>To address this, this plugin keeps a record of the last known sync state of local and remote files. During syncing evaluates <strong>three states (current local, current remote, recorded local and remote in last sync)</strong> for each file path and decides the sync action accordingly:</p><blockquote><p>✅ = Exists, ❌ = Doesn&#39;t Exist, ✏️ = Changed Compared to Record</p></blockquote><table tabindex="0"><thead><tr><th>Cases</th><th style="text-align:center;">Local File</th><th style="text-align:center;">Remote File</th><th style="text-align:center;">Sync Record</th><th>Action</th></tr></thead><tbody><tr><td>1</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td>⏭️ <strong>Skip</strong> (already synced)</td></tr><tr><td>2</td><td style="text-align:center;">✏️</td><td style="text-align:center;">✏️</td><td style="text-align:center;">✅</td><td>⚠️ <strong>Resolve Conflict</strong> (apply strategy)</td></tr><tr><td>3</td><td style="text-align:center;">✅</td><td style="text-align:center;">✏️</td><td style="text-align:center;">✅</td><td>⬇️ <strong>Pull</strong> (download remote)</td></tr><tr><td>4</td><td style="text-align:center;">✏️</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td>⬆️ <strong>Push</strong> (upload local)</td></tr><tr><td>5</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅</td><td>🗑️ <strong>Delete Local</strong> (cleanup)</td></tr><tr><td>6</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td>🗑️ <strong>Delete Remote</strong> (cleanup)</td></tr><tr><td>7</td><td style="text-align:center;">❌</td><td style="text-align:center;">✏️</td><td style="text-align:center;">✅</td><td>⬇️ <strong>Pull</strong> (restore from remote)</td></tr><tr><td>8</td><td style="text-align:center;">✏️</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅</td><td>⬆️ <strong>Push</strong> (restore to remote)</td></tr><tr><td>9</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅ (comparing with local)</td><td style="text-align:center;">❌</td><td>📝 <strong>Record</strong> (capture unrecorded file)</td></tr><tr><td>10</td><td style="text-align:center;">✅</td><td style="text-align:center;">✏️ (compared with local)</td><td style="text-align:center;">❌</td><td>⚠️ <strong>Resolve Conflict</strong> (first sync)</td></tr><tr><td>11</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td>⬇️ <strong>Pull</strong> (new remote file)</td></tr><tr><td>12</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td><td>⬆️ <strong>Push</strong> (new local file)</td></tr><tr><td>13</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅</td><td>🧹 <strong>Clean Record</strong> (database cleanup)</td></tr></tbody></table><h3 id="encryption" tabindex="-1">Encryption <a class="header-anchor" href="#encryption" aria-label="Permalink to “Encryption”">​</a></h3><p>Client-side encryption is the <strong>most rigorously designed</strong> part in the plugin. Encryption is not as simple as using a key to encode a part of file, which can be broken by attackers within minutes. The real encryption process in WebDAV Sync involves <strong>multiple layers of confusion and diffusion</strong>, as shown in the diagram below.</p>',28)),d(s,{canvas:c(a)},null,8,["canvas"]),e[1]||(e[1]=t('<p>The use of WebDAV server information in salting user&#39;s password avoids risks brought by Rclone-style universal fixed salt. By choosing <code>AES-GCM-SIV-256</code> as the deterministic algorithm for file path encryption, and directly weaving files paths and sizes into file encryption keys, the algorithm can maximally validate the integrity of downloaded files, as well as detecting malicious file movement and truncation.</p><p>The resulting encryption pipeline is <strong>theoretically more secure, fast, and Obsidian-native</strong> than similar solutions (like Rclone Crypt), and competitor plugins (like Remotely Save, which uses Crypt under the hood).</p><h3 id="something-more" tabindex="-1">Something More <a class="header-anchor" href="#something-more" aria-label="Permalink to “Something More”">​</a></h3><p>There&#39;s more things to delve into the technological aspect of this plugin.</p><p>For example, comparing four states before syncing means we need a <strong>whole WebDAV, local vault and record traversal at the start of each sync</strong>, which is impractical for large vaults. To address this, <strong>Fast Mode</strong> is introduced that reuses the remote state in the record as current state, which avoids traversing the whole WebDAV each sync. Fast mode is enabled by default for real-time syncs and a normal sync (which is triggered by manual, periodic, or startup sync) is recommended before fast mode syncs.</p><p>Moreover, to store the records and content of all files (to compare and decide whether a file is changed) requires a huge and active amount of storage to ensure fidelity. This plugin leverages IndexedDB to store the records and query them on-demand.</p><p>Also, to control memory usage and prevent crashes when downloading large files, this plugin has specialized <strong>load balancing and download chunking</strong> mechanisms. When a file has size larger than a user-configured threshold, the plugin will split the files into chunks and download in parallel, and save them immediately in local cache when each chunk is finished. In the final pass, the plugin sorts the cache and writes the complete file incrementally. This not only ensures the memory consumption at a constant low level when handling gigabytes of file, also makes large file downloading fully resumable.</p><h2 id="installation-setup" tabindex="-1">Installation &amp; Setup <a class="header-anchor" href="#installation-setup" aria-label="Permalink to “Installation &amp; Setup”">​</a></h2><p>Since the plugin is currently in beta, installation requires the <strong>BRAT</strong> (Beta Reviewer Auto-update Tool) plugin:</p><h3 id="step-1-install-brat" tabindex="-1">Step 1: Install BRAT <a class="header-anchor" href="#step-1-install-brat" aria-label="Permalink to “Step 1: Install BRAT”">​</a></h3><ol><li>Open Obsidian Settings → Community Plugins</li><li>Search for and install <strong>BRAT</strong></li><li>Enable the plugin</li></ol><h3 id="step-2-add-obsidian-webdav-sync" tabindex="-1">Step 2: Add Obsidian WebDAV Sync <a class="header-anchor" href="#step-2-add-obsidian-webdav-sync" aria-label="Permalink to “Step 2: Add Obsidian WebDAV Sync”">​</a></h3><ol><li>Open BRAT settings</li><li>Click <strong>Add beta plugin</strong></li><li>Paste repository URL: <code>https://github.com/hesprs/obsidian-webdav-sync</code></li><li>Select the latest version and click <strong>Add plugin</strong></li></ol><h3 id="step-3-configure-webdav-connection" tabindex="-1">Step 3: Configure WebDAV Connection <a class="header-anchor" href="#step-3-configure-webdav-connection" aria-label="Permalink to “Step 3: Configure WebDAV Connection”">​</a></h3><ol><li>Enter your WebDAV server URL</li><li>Provide account credentials</li><li>Click <strong>Check connection</strong> to verify</li><li>Select your remote directory</li><li>Initiate your first sync</li></ol><blockquote><p>Always backup important notes before your initial sync. While the plugin handles file presence resolution robustly, having a backup provides peace of mind during first-time setup.</p></blockquote><h2 id="license" tabindex="-1">License <a class="header-anchor" href="#license" aria-label="Permalink to “License”">​</a></h2><p>Obsidian WebDAV Sync is licensed under the <a href="https://www.gnu.org/licenses/agpl-3.0.en.html" target="_blank" rel="noreferrer">AGPL-3.0 License</a>.</p>',18))]))}});export{w as __pageData,x as default};
